-- ============================================================================
-- Community Projects — WordPress Content Migration
-- ============================================================================
-- Run with:
--   npx wrangler d1 execute soard-db --remote --file=scripts/migrate-community-content.sql
--
-- This adds story text, before/after photos, partner logos, and detail page
-- fields to the 4 community projects migrated from WordPress.
-- Existing entries (the-drake-house, childrens-development-academy) are updated.
-- New entries (the-cottage-school, mt-zion-umc-preschool) are inserted.
-- ============================================================================

-- ─── The Cottage School (2021) ───────────────────────────────────────────────
INSERT OR REPLACE INTO community (slug, name, order_num, data) VALUES (
  'the-cottage-school',
  'The Cottage School',
  3,
  '{"name":"The Cottage School","slug":"the-cottage-school","impact":"200+","impactLabel":"students supported","year":"2021","description":"The Cottage School provides an educational environment for students in grades 4–12 with a wide variety of special needs. SOARD renovated their main office lobby — the very first space prospective families see — transforming it into a warm, welcoming environment that sets the tone for healing and belonging.","color":"#4A148C","imageId":"community/the-cottage-school/after-01","imageAlt":"The Cottage School lobby renovated by SOARD","order":3,"founded":"1985","heroImage":"community/the-cottage-school/after-01","metaDescription":"See how Sunshine on a Ranney Day partnered with The Cottage School to renovate their main lobby into a warm, welcoming space for students and families.","story":"The Cottage School (TCS) is a school that provides an educational environment for students in grades 4–12 with a wide variety of special needs. In addition to struggling academically, socially, and emotionally, many of their students arrive broken in spirit. Their program works on building students'' self-confidence, self-determination, and helping each one find their voice. The Cottage School prepares individuals for fulfillment of their true and tremendous potential as confident, productive, and independent adults.\n\nThe Cottage School was delighted to partner with Sunshine on a Ranney Day for the makeover of their main office lobby area. Two Atlanta-area nonprofits working together to help support children with special needs — they couldn''t think of a better match.\n\nThis project is so much more than a \"face-lift.\" The design area is the first stop for prospective students and their families as they search for that soft-landing spot after struggling in prior environments. This initial meeting can be rather emotional as background information and struggles are discussed. The school had long dreamt of meeting with these families in a warm, comfortable setting where they immediately feel the sense of community and comfort they have been searching for.","quote":"It is our differences that make us a community… but our similarities that make us a family.","beforePhotos":[{"url":"community/the-cottage-school/before-01","alt":"The Cottage School lobby before renovation"},{"url":"community/the-cottage-school/before-02","alt":"The Cottage School office area before renovation"},{"url":"community/the-cottage-school/before-03","alt":"The Cottage School meeting area before renovation"},{"url":"community/the-cottage-school/before-04","alt":"The Cottage School entrance before renovation"},{"url":"community/the-cottage-school/before-05","alt":"The Cottage School reception before renovation"}],"afterPhotos":[{"url":"community/the-cottage-school/after-01","alt":"The Cottage School renovated lobby entrance"},{"url":"community/the-cottage-school/after-02","alt":"Renovated lobby seating area"},{"url":"community/the-cottage-school/after-03","alt":"Custom wall art and mural in renovated space"},{"url":"community/the-cottage-school/after-04","alt":"New reception desk and gathering area"},{"url":"community/the-cottage-school/after-05","alt":"Warm lighting and comfortable furniture in lobby"},{"url":"community/the-cottage-school/after-06","alt":"Community bulletin and welcome area"},{"url":"community/the-cottage-school/after-07","alt":"Renovated hallway with new design elements"},{"url":"community/the-cottage-school/after-08","alt":"Finished meeting space for families"},{"url":"community/the-cottage-school/after-09","alt":"Completed lobby renovation overview"},{"url":"community/the-cottage-school/after-10","alt":"Detail of new design in lobby"}],"photos":[],"partnerLogos":[{"url":"https://sunshineonaranneyday.com/wp-content/uploads/2021/06/logo_kids_r_kids.png","name":"Kids R Kids"},{"url":"https://sunshineonaranneyday.com/wp-content/uploads/2021/06/logo_crosby_design_group.png","name":"Crosby Design Group"},{"url":"https://sunshineonaranneyday.com/wp-content/uploads/2021/06/logo_reliable_heatingair.png","name":"Reliable Heating & Air"},{"url":"https://sunshineonaranneyday.com/wp-content/uploads/2021/10/logo_randall_brothers.png","name":"Randall Brothers"},{"url":"https://sunshineonaranneyday.com/wp-content/uploads/2021/06/logo_us_cabinetworks.png","name":"US Cabinetworks"},{"url":"https://sunshineonaranneyday.com/wp-content/uploads/2021/06/logo_cambria.png","name":"Cambria"},{"url":"https://sunshineonaranneyday.com/wp-content/uploads/2021/06/logo_cr_construction.png","name":"CR Construction"},{"url":"https://sunshineonaranneyday.com/wp-content/uploads/2022/01/logo_sunny__ranney.png","name":"Sunny & Ranney"},{"url":"https://sunshineonaranneyday.com/wp-content/uploads/2022/01/logo_shaw_floors.png","name":"Shaw Floors"},{"url":"https://sunshineonaranneyday.com/wp-content/uploads/2021/06/logo_real_floors_commercial.png","name":"Real Floors Commercial"},{"url":"https://sunshineonaranneyday.com/wp-content/uploads/2021/06/logo_wall_nut_custom_wall_murals.png","name":"The Wall Nut"},{"url":"https://sunshineonaranneyday.com/wp-content/uploads/2021/06/logo_legacy_lighting.png","name":"Legacy Lighting"},{"url":"https://sunshineonaranneyday.com/wp-content/uploads/2021/07/logo_five_star_painting.png","name":"Five Star Painting"},{"url":"https://sunshineonaranneyday.com/wp-content/uploads/2021/07/logo_bin_there_dump_that.png","name":"Bin There Dump That"},{"url":"https://sunshineonaranneyday.com/wp-content/uploads/2021/06/logo_nicole_photography.png","name":"Nicole Photography"},{"url":"https://sunshineonaranneyday.com/wp-content/uploads/2021/06/logo_nothing_bundt_cakes.png","name":"Nothing Bundt Cakes"},{"url":"https://sunshineonaranneyday.com/wp-content/uploads/2021/06/logo_iframe_media.png","name":"iFrame Media"}]}'
);

-- ─── The Drake House (2022) ──────────────────────────────────────────────────
INSERT OR REPLACE INTO community (slug, name, order_num, data) VALUES (
  'the-drake-house',
  'The Drake House',
  4,
  '{"name":"The Drake House","slug":"the-drake-house","impact":"250","impactLabel":"families served","year":"2022","description":"The Drake House provides housing and education for single mothers and their children experiencing homelessness in North Metro Atlanta. SOARD renovated their main headquarters — redesigning classrooms, activity spaces, a community kitchen, and teen gathering rooms to create an environment where families can recover, learn, and rebuild with dignity.","color":"#C62828","imageId":"community/the-drake-house/after-01","imageAlt":"The Drake House headquarters renovated by SOARD","order":4,"founded":"2006","heroImage":"community/the-drake-house/after-01","metaDescription":"See how Sunshine on a Ranney Day renovated The Drake House headquarters — classrooms, a community kitchen, and teen spaces for families overcoming homelessness.","story":"Founded in 2006, The Drake House provides housing and education programs for single mothers and their children who are experiencing homelessness in North Metro Atlanta. It is a community where every family has the opportunity to recover quickly and with dignity from their homeless situation.\n\nEach year Sunshine on a Ranney Day completes a special community project that helps a large number of children and families. SOARD was excited to help The Drake House by renovating their main headquarters. This makeover included redesigning and renovating multiple rooms that serve as classrooms for kids studying, learning life skills, arts and crafts, and safe spaces for them to lounge. The rooms also serve to help moms with relationship building, parenting, health and wellness, and money management.\n\nThe goal of the makeover was to create flexible-use spaces that allow the children to feel at home in a learning and activity environment. The spaces also help keep the community of kids engaged with each other, creating an extended ''family'' feel. The central community space in the basement is the food serving area — previously extremely cramped without a natural flow, inhibiting the ability to smoothly cater to families participating in the buffet line. SOARD created this natural flow through relocation of structural walls and the addition of a large island space.\n\nThere was not previously a dedicated space for older children and teens to gather for free time and engage with The Drake House volunteers for tutoring. SOARD converted the upstairs executive offices into that space, providing a leisure area as well as a learning and meeting space.","quote":"Over 40% of Atlanta''s homeless population are women and children.","beforePhotos":[{"url":"community/the-drake-house/before-01","alt":"The Drake House kitchen area before renovation"},{"url":"community/the-drake-house/before-02","alt":"The Drake House classroom before renovation"},{"url":"community/the-drake-house/before-03","alt":"The Drake House common area before renovation"},{"url":"community/the-drake-house/before-04","alt":"The Drake House office space before renovation"}],"afterPhotos":[{"url":"community/the-drake-house/after-01","alt":"The Drake House renovated gathering space"},{"url":"community/the-drake-house/after-02","alt":"Renovated learning area with new furniture"},{"url":"community/the-drake-house/after-03","alt":"New classroom space for children"},{"url":"community/the-drake-house/after-04","alt":"SOARD team at The Drake House reveal"},{"url":"community/the-drake-house/after-05","alt":"Renovated community kitchen with island"},{"url":"community/the-drake-house/after-06","alt":"Drake House reveal celebration"},{"url":"community/the-drake-house/after-07","alt":"New teen hangout and study space"},{"url":"community/the-drake-house/after-08","alt":"Renovated hallway with fresh design"},{"url":"community/the-drake-house/after-09","alt":"Activity room for kids at Drake House"},{"url":"community/the-drake-house/after-10","alt":"New seating area in community space"},{"url":"community/the-drake-house/after-11","alt":"Completed renovation detail"}],"photos":[],"partnerLogos":[{"url":"https://sunshineonaranneyday.com/wp-content/uploads/2021/06/logo_jackson_healthcare.png","name":"Jackson Healthcare"},{"url":"https://sunshineonaranneyday.com/wp-content/uploads/2021/06/logo_randall_paulson.png","name":"Randall Paulson Architects"},{"url":"https://sunshineonaranneyday.com/wp-content/uploads/2021/06/logo_real_floors_commercial.png","name":"Real Floors Commercial"},{"url":"https://sunshineonaranneyday.com/wp-content/uploads/2021/10/logo_randall_brothers.png","name":"Randall Brothers"},{"url":"https://sunshineonaranneyday.com/wp-content/uploads/2022/10/logo_sugar_hill_outdoors.png","name":"Sugar Hill Outdoors"},{"url":"https://sunshineonaranneyday.com/wp-content/uploads/2021/06/logo_mohawk.png","name":"Mohawk"},{"url":"https://sunshineonaranneyday.com/wp-content/uploads/2022/11/logo_envision_office_solutions.png","name":"Envision Office Solutions"},{"url":"https://sunshineonaranneyday.com/wp-content/uploads/2022/07/logo_builders_cabinet_company.png","name":"Builders Cabinet Company"},{"url":"https://sunshineonaranneyday.com/wp-content/uploads/2022/10/logo_rexel_foundation.png","name":"Rexel Foundation"},{"url":"https://sunshineonaranneyday.com/wp-content/uploads/2021/06/logo_cambria.png","name":"Cambria"},{"url":"https://sunshineonaranneyday.com/wp-content/uploads/2021/07/logo_cr_construction_v2.png","name":"CR Construction"},{"url":"https://sunshineonaranneyday.com/wp-content/uploads/2021/06/logo_echols.png","name":"Echols"},{"url":"https://sunshineonaranneyday.com/wp-content/uploads/2022/10/logo_tlc_engineering.png","name":"TLC Engineering"},{"url":"https://sunshineonaranneyday.com/wp-content/uploads/2023/01/logo_3lp_engineering.jpg","name":"3LP Engineering"},{"url":"https://sunshineonaranneyday.com/wp-content/uploads/2021/10/logo_emser_tile.jpg","name":"Emser Tile"},{"url":"https://sunshineonaranneyday.com/wp-content/uploads/2021/06/logo_wall_nut_custom_wall_murals.png","name":"The Wall Nut"},{"url":"https://sunshineonaranneyday.com/wp-content/uploads/2021/06/logo_comfort_research.png","name":"Comfort Research"},{"url":"https://sunshineonaranneyday.com/wp-content/uploads/2021/06/logo_atlas_disposal.png","name":"Atlas Disposal"},{"url":"https://sunshineonaranneyday.com/wp-content/uploads/2022/10/logo_cosentino.png","name":"Cosentino"},{"url":"https://sunshineonaranneyday.com/wp-content/uploads/2022/10/logo_mri_software.svg.png","name":"MRI Software"},{"url":"https://sunshineonaranneyday.com/wp-content/uploads/2022/06/logo_roswell_womens_club.webp","name":"Roswell Woman''s Club"},{"url":"https://sunshineonaranneyday.com/wp-content/uploads/2022/10/logo_alpharetta_rotary.jpg","name":"Alpharetta Rotary"},{"url":"https://sunshineonaranneyday.com/wp-content/uploads/2022/10/logo_ids_demo.png","name":"IDS Demo"},{"url":"https://sunshineonaranneyday.com/wp-content/uploads/2022/10/logo_jk_electrical.png","name":"JK Electrical"},{"url":"https://sunshineonaranneyday.com/wp-content/uploads/2022/10/logo_tko_plumbing.webp","name":"TKO Plumbing"},{"url":"https://sunshineonaranneyday.com/wp-content/uploads/2022/10/logo_baker_paint.png","name":"Baker Paint"},{"url":"https://sunshineonaranneyday.com/wp-content/uploads/2021/06/logo_swinerton.png","name":"Swinerton"},{"url":"https://sunshineonaranneyday.com/wp-content/uploads/2021/06/logo_nicole_photography.png","name":"Nicole Photography"},{"url":"https://sunshineonaranneyday.com/wp-content/uploads/2021/06/logo_nothing_bundt_cakes.png","name":"Nothing Bundt Cakes"}]}'
);

-- ─── Mt. Zion UMC Preschool (2024) ──────────────────────────────────────────
INSERT OR REPLACE INTO community (slug, name, order_num, data) VALUES (
  'mt-zion-umc-preschool',
  'Mt. Zion UMC Preschool',
  5,
  '{"name":"Mt. Zion UMC Preschool","slug":"mt-zion-umc-preschool","impact":"500+","impactLabel":"children impacted yearly","year":"2024","description":"Mt. Zion United Methodist Church Preschool is known as ''the loving school in the heart of East Cobb.'' SOARD created a calming sensory therapy space with dimmable lighting, a custom climbing tower, climbing wall, and sensory equipment — serving hundreds of children today and in the future.","color":"#1B5E20","imageId":"community/mt-zion-umc-preschool/after-01","imageAlt":"Mt. Zion UMC Preschool sensory room renovated by SOARD","order":5,"founded":"1973","heroImage":"community/mt-zion-umc-preschool/after-01","metaDescription":"See how Sunshine on a Ranney Day built a calming sensory therapy space at Mt. Zion UMC Preschool with a climbing tower, climbing wall, and sensory equipment.","story":"In 1973, Mt. Zion United Methodist Church opened one of the first preschools in the East Cobb area. Today the program continues to be known for its commitment to quality early childhood education and loving care for children from 12 months through 5 years of age. Since its inception, the preschool has been recognized for its commitment to excellence in early childhood education. It has earned national recognition as a N.A.E.Y.C. accredited program and is also recognized as a ''School of Excellence'' by the North Georgia UMC Conference.\n\nMt. Zion UMC Preschool is known as ''the loving school in the heart of East Cobb.'' The goal of this makeover was to create a calming sensory therapy space for students attending Mt. Zion. Through a prior partnership with the Adaptive Learning Center, Mt. Zion has become known for excellence in the sensory special needs education space and has recently partnered with an in-house licensed occupational therapist to provide adaptive services for their students.\n\nBy providing dimmable lighting, a custom climbing and cool-down tower, a custom climbing wall, and various therapy and sensory equipment features, SOARD was able to provide this therapy space that will serve hundreds of kids today and in the future.","quote":"Mt. Zion UMC Preschool is known as ''the loving school in the heart of East Cobb.''","beforePhotos":[{"url":"community/mt-zion-umc-preschool/before-01","alt":"Mt. Zion room before renovation — empty space"},{"url":"community/mt-zion-umc-preschool/before-02","alt":"Mt. Zion room before renovation — bare walls"},{"url":"community/mt-zion-umc-preschool/before-03","alt":"Mt. Zion room before renovation — original state"}],"afterPhotos":[{"url":"community/mt-zion-umc-preschool/after-01","alt":"Completed sensory therapy room overview"},{"url":"community/mt-zion-umc-preschool/after-02","alt":"Custom climbing tower and cool-down space"},{"url":"community/mt-zion-umc-preschool/after-03","alt":"Sensory wall with interactive elements"},{"url":"community/mt-zion-umc-preschool/after-04","alt":"Dimmable lighting and calming design"},{"url":"community/mt-zion-umc-preschool/after-05","alt":"Custom climbing wall for occupational therapy"},{"url":"community/mt-zion-umc-preschool/after-06","alt":"Therapy equipment and sensory features"},{"url":"community/mt-zion-umc-preschool/after-07","alt":"Detail of sensory room design"},{"url":"community/mt-zion-umc-preschool/after-08","alt":"Celebration at reveal event"},{"url":"community/mt-zion-umc-preschool/after-09","alt":"Teachers and staff at reveal"},{"url":"community/mt-zion-umc-preschool/after-10","alt":"Children enjoying the new sensory space"},{"url":"community/mt-zion-umc-preschool/after-11","alt":"Wide view of completed therapy room"},{"url":"community/mt-zion-umc-preschool/after-12","alt":"Climbing and activity area"},{"url":"community/mt-zion-umc-preschool/after-13","alt":"Cool-down and reading nook"},{"url":"community/mt-zion-umc-preschool/after-14","alt":"Final reveal moment"}],"photos":[],"partnerLogos":[{"url":"https://sunshineonaranneyday.com/wp-content/uploads/2024/09/Logo_jm_wilkerson_construction.png","name":"JM Wilkerson Construction"},{"url":"https://sunshineonaranneyday.com/wp-content/uploads/2024/06/logo_artisan_design_studio.webp","name":"Artisan Design Studio"},{"url":"https://sunshineonaranneyday.com/wp-content/uploads/2024/08/logo_construction_partner_the_wall_nut.png","name":"The Wall Nut"},{"url":"https://sunshineonaranneyday.com/wp-content/uploads/2024/05/logo_baker_paint.png","name":"Baker Paint"},{"url":"https://sunshineonaranneyday.com/wp-content/uploads/2024/05/logo_sherwin_williams-2.png","name":"Sherwin-Williams"},{"url":"https://sunshineonaranneyday.com/wp-content/uploads/2024/09/logo_construction_partner_bin_there_dump_that.png","name":"Bin There Dump That"},{"url":"https://sunshineonaranneyday.com/wp-content/uploads/2024/08/logo_construction_partner_servicewise_electric.png","name":"ServiceWise Electric"}]}'
);

-- ─── Children's Development Academy (2025) ───────────────────────────────────
INSERT OR REPLACE INTO community (slug, name, order_num, data) VALUES (
  'childrens-development-academy',
  'Children''s Development Academy',
  6,
  '{"name":"Children''s Development Academy","slug":"childrens-development-academy","impact":"100+","impactLabel":"children enrolled","year":"2025","description":"Founded in 1967, the CDA in Roswell gives young children the best chance to read on grade level by third grade, graduate high school, and break the cycle of generational poverty. SOARD is part of the CDA''s Learn.Play.Serve campaign — creating a new toddler classroom and community room with architecture by Randall Paulson, design by Crosby Design Group, and construction by Trident Construction.","color":"#00838F","badge":"In Progress","imageId":"community/childrens-development-academy/before-01","imageAlt":"Children''s Development Academy building before renovation","order":6,"founded":"1967","heroImage":"community/childrens-development-academy/before-01","metaDescription":"Sunshine on a Ranney Day is partnering with the Children''s Development Academy in Roswell to create a new toddler classroom and community room as part of their Learn.Play.Serve campaign.","story":"In 1967, the Children''s Development Academy''s founders were driven by the belief that the best way to eradicate generational poverty was to start with the children. Today, the CDA gives young children the very best chance to read on grade level by the third grade, graduate from high school, attend college, and achieve other life-altering goals.\n\nSunshine on a Ranney Day is excited to be part of the CDA''s Learn.Play.Serve campaign which will involve an extensive remodel to the CDA''s current building. SOARD is organizing amazing partners to help create a new toddler classroom which will allow more children to enter the program, and a new community room which will be used by the CDA for programs and meetings.\n\nSOARD has organized some of our amazing partners to work with the CDA to complete this project. Randall Paulson handled the architecture, Crosby Design Group the design, and Trident Construction will be handling the construction.","quote":null,"beforePhotos":[{"url":"community/childrens-development-academy/before-01","alt":"CDA building exterior before renovation"},{"url":"community/childrens-development-academy/before-02","alt":"CDA interior classroom before renovation"},{"url":"community/childrens-development-academy/before-03","alt":"CDA hallway before renovation"},{"url":"community/childrens-development-academy/before-04","alt":"CDA room to be converted to toddler classroom"},{"url":"community/childrens-development-academy/before-05","alt":"CDA space to be converted to community room"},{"url":"community/childrens-development-academy/before-06","alt":"CDA building detail before renovation"}],"afterPhotos":[],"photos":[],"partnerLogos":[{"url":"https://sunshineonaranneyday.com/wp-content/uploads/2021/06/logo_randall_paulson.png","name":"Randall Paulson Architects"},{"url":"https://sunshineonaranneyday.com/wp-content/uploads/2021/06/logo_crosby_design_group-e1742500582203.png","name":"Crosby Design Group"},{"url":"https://sunshineonaranneyday.com/wp-content/uploads/2026/01/Trident_ESOP__Horizontal-Color-scaled.png","name":"Trident Construction"}]}'
);
